package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.PrintStream;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private final PrintStream originalOut = System.out;
    private TestPrintStream testOut;

    @BeforeEach
    void setUp() {
        testOut = new TestPrintStream();
        System.setOut(testOut);
    }

    @AfterEach
    void tearDown() {
        System.setOut(originalOut);
    }

    @Test
    void testPrinterReturnsCSVPrinterWithSystemOutAndThisFormat() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVPrinter printer = format.printer();
        assertNotNull(printer);
        // Check that the printer's out is System.out by printing something and checking output
        String testString = "test";
        printer.print(testString);
        printer.flush();
        assertTrue(testOut.getContent().contains(testString));
    }

    // Helper class to capture System.out prints
    private static class TestPrintStream extends PrintStream {
        private final StringBuilder content = new StringBuilder();

        TestPrintStream() {
            super(System.out);
        }

        @Override
        public void print(String s) {
            content.append(s);
            super.print(s);
        }

        @Override
        public void println(String s) {
            content.append(s).append(System.lineSeparator());
            super.println(s);
        }

        String getContent() {
            return content.toString();
        }
    }
}
